#include<bits/stdc++.h>
using namespace std;
struct node
{
	int a,b;
	bool operator<(const node&x)const
	{
		return a>x.a;
	}
}a[10001];
int main()
{
	priority_queue<int,vector<int>,less<int>> q;
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d%d",&a[i].a,&a[i].b);
	}
	sort(a+1,a+1+n);
	int l,p;
	scanf("%d%d",&l,&p);
	int ans=0;
	int pos=1;
	l-=p;
	while(l>0)
	{
		while(l<=a[pos].a)
		{
			q.push(a[pos].b);
			pos++;
		}
		if(q.empty())
		{
			printf("-1");
			return 0;
		}
		l-=q.top();
		q.pop();
		ans++;
	}
	printf("%d",ans);
	return 0;
}
